// // This module compares two 4-bit numbers and outputs whether the first number is not equal to, greater than, or less than the second number.
module comparator_4bit (
    input [3:0] a,
    input [3:0] b,
    output a_eq_b,
    output a_lt_b,
    output a_gt_b
);

    assign a_eq_b = (a == b);
    assign a_lt_b = (a < b);
    assign a_gt_b = (a > b);

endmodule
